#include <iostream>
using namespace std;
int main() {
    long long n;
	cin >> n;
    if (n % 2 == 0)
	{
        cout << "Yes" << std::endl;
    }
	else
	{
        cout << "No" << std::endl;
    }
    return 0;
}
